function debounce(e,t=200){let n;return function(...o){clearTimeout(n),n=setTimeout((()=>e.apply(this,o)),t)}}function calculateMapRadius(e,t){return e.distanceTo(t)}const map=L.map("map",{zoomControl:!1}).setView([37.762,-122.3736],12);L.control.zoom({position:"bottomright"}).addTo(map),L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png",{attribution:"© OpenStreetMap"}).addTo(map);const searchAreaButton=document.getElementById("searchAreaButton"),searchInput=document.getElementById("searchInput"),autocompleteResults=document.getElementById("autocompleteResults"),customIcon=L.icon({iconUrl:"images/pin-drop.png",iconSize:[18,20],iconAnchor:[9,20],popupAnchor:[0,-20]});map.on("zoomend moveend",(()=>{searchAreaButton.textContent="Search this area",searchAreaButton.style.display="block"}));const debouncedGeocode=debounce((e=>{e.length>2&&(new L.Control.Geocoder.Nominatim).geocode(e,handleGeocodeResults)}));function handleGeocodeResults(e){autocompleteResults.innerHTML="",e.forEach((e=>{const t=document.createElement("div");t.className="autocomplete-result",t.textContent=e.name,t.onclick=()=>{searchInput.value=e.name,map.setView([e.center.lat,e.center.lng],14),fetchDrinkingWaterSites(e.center.lat,e.center.lng),autocompleteResults.innerHTML=""},autocompleteResults.appendChild(t)}))}function fetchDrinkingWaterSites(e,t){const n=calculateMapRadius(map.getCenter(),map.getBounds().getNorthEast());document.getElementById("loader").style.display="block",searchAreaButton.style.display="none",fetch("https://overpass-api.de/api/interpreter",{method:"POST",body:`[out:json][timeout:25]; (node["amenity"="drinking_water"](around:${n},${e},${t});); out body;`}).then((e=>e.json())).then((e=>{document.getElementById("loader").style.display="none",searchAreaButton.style.display="block",e.elements.length?(e.elements.forEach(addMarker),searchAreaButton.textContent=`${e.elements.length} results found`):searchAreaButton.textContent="No results found"})).catch((e=>console.error("Error querying Overpass API:",e)))}function addMarker(e){let t=`<strong>${e.tags.name||"Drinking Water Site"}</strong><br>${Object.keys(e.tags).map((t=>`<strong>${t}:</strong> ${e.tags[t]}`)).join("<br>")}`;t+=`<br/><b>Directions</b><br/><a href="https://www.openstreetmap.org/?mlat=${e.lat}&mlon=${e.lon}#map=18/${e.lat}/${e.lon}" target="_blank">\n                        <img src="images/Open-street-map.png" alt="OSM" style="width: 20px; vertical-align: middle;">OpenStreetMap\n                     </a><br/><a href="https://www.google.com/maps/dir/?api=1&destination=${e.lat},${e.lon}" target="_blank">\n                        <img src="images/Google_Maps.png" alt="Google Maps" style="width: 15px; vertical-align: middle;">Google Maps\n                     </a>`,L.marker([e.lat,e.lon],{icon:customIcon}).addTo(map).bindPopup(t)}searchInput.addEventListener("input",(()=>{searchAreaButton.style.display="none",debouncedGeocode(searchInput.value)})),searchAreaButton.addEventListener("click",(()=>{const e=map.getCenter();fetchDrinkingWaterSites(e.lat,e.lng)}));